184→  async init(): Promise<void> {
185→    await initI18n();
186→    const ok = await this.findCriticalElements();
187→    if (!ok) return;
188→    this.injectTimelineUI();
189→    this.setupEventListeners();
190→    this.setupObservers();
191→    this.conversationId = this.computeConversationId();
192→    await this.loadStars();
193→    await this.syncStarredFromService();
194→    this.loadMarkerLevels();
195→    this.loadCollapsedMarkers();
196→    // Ensure initial render even when Gemini DOM is already stable (no mutations after observer attaches)
197→    this.recalculateAndRenderMarkers();
198→    // Handle URL hash for starred message navigation
199→    this.handleStarredMessageNavigation();
200→    // Initialize keyboard shortcuts
201→    await this.initKeyboardShortcuts();
202→    try {
203→      const g = globalThis as ExtGlobal;
204→      const defaults = {
205→        geminiTimelineScrollMode: 'flow',
206→        geminiTimelineHideContainer: false,
207→        geminiTimelineDraggable: false,
208→        geminiTimelineMarkerLevel: false,
209→        geminiTimelinePosition: null,
210→        [StorageKeys.LANGUAGE]: null,
211→      };
212→
213→      let res: Record<string, unknown> | null = null;
214→      // prefer chrome.storage or browser.storage if available to sync with popup
215→      if (g.chrome?.storage?.sync || g.browser?.storage?.sync) {
216→        res = await new Promise((resolve) => {
217→          if (g.chrome?.storage?.sync?.get) {
218→            g.chrome.storage.sync.get(
219→              defaults as Record<string, unknown>,
220→              (items: Record<string, unknown>) => {
221→                if (g.chrome.runtime.lastError) {
222→                  console.error(
223→                    `[Timeline] chrome.storage.get failed: ${g.chrome.runtime.lastError.message}`,
224→                  );
225→                  resolve(null);
226→                } else {
227→                  resolve(items);
228→                }
229→              },
230→            );
231→          } else {
232→            g.browser?.storage?.sync
233→              ?.get(defaults)
234→              .then(resolve)
235→              .catch((error: Error) => {
236→                console.error(`[Timeline] browser.storage.get failed: ${error.message}`);
237→                resolve(null);
238→              });
239→          }
240→        });
241→      } else {
242→        // No extension storage available, try to load critical fallback from localStorage
243→        const saved = localStorage.getItem('geminiTimelineScrollMode');
244→        if (saved === 'flow' || saved === 'jump') res = { geminiTimelineScrollMode: saved };
245→      }
246→
247→      const m = res?.geminiTimelineScrollMode;
248→      if (m === 'flow' || m === 'jump') this.scrollMode = m;
249→      this.hideContainer = !!res?.geminiTimelineHideContainer;
250→      this.applyContainerVisibility();
251→      this.toggleDraggable(!!res?.geminiTimelineDraggable);
252→      this.toggleMarkerLevel(!!res?.geminiTimelineMarkerLevel);
253→      this.rtl = applyRTLClass(res?.[StorageKeys.LANGUAGE] as string | null | undefined);
254→
255→      // Load position with auto-migration from v1 to v2
256→      const position = res?.geminiTimelinePosition as
257→        | {
258→            version?: number;
259→            topPercent?: number;
260→            leftPercent?: number;
261→            top?: number;
262→            left?: number;
263→          }
264→        | undefined;
265→      if (position) {
266→        const viewportWidth = window.innerWidth;
267→        const viewportHeight = window.innerHeight;
268→
269→        // v2 format: use percentage (responsive)
270→        if (
271→          position.version === 2 &&
272→          position.topPercent !== undefined &&
273→          position.leftPercent !== undefined
274→        ) {
275→          const top = (position.topPercent / 100) * viewportHeight;
276→          const left = (position.leftPercent / 100) * viewportWidth;
277→          this.applyPosition(top, left);
278→        }
279→        // v1 format: migrate to v2 (auto-upgrade)
