469→  private getConversationTitle(): string {
470→    const getText = (el: Element | null | undefined): string | null => {
471→      const text = el?.textContent?.trim();
472→      return text && text.length > 0 ? text : null;
473→    };
474→
475→    // Strategy 1: Prefer the currently selected conversation in folder view
476→    try {
477→      const selected = document.querySelector(
478→        '.gv-folder-conversation-selected .gv-conversation-title',
479→      );
480→      const title = getText(selected);
481→      if (title) return title;
482→    } catch (error) {
483→      console.debug('[Timeline] Failed to get title from selected folder conversation:', error);
484→    }
485→
486→    // Strategy 2: Try to get from page title
487→    const titleElement = document.querySelector('title');
488→    if (titleElement) {
489→      const title = titleElement.textContent?.trim();
490→      // Filter out generic titles
491→      if (
492→        title &&
493→        title !== 'Gemini' &&
494→        title !== 'Google Gemini' &&
495→        title !== 'Google AI Studio' &&
496→        !title.startsWith('Gemini -') &&
497→        !title.startsWith('Google AI Studio -') &&
498→        title.length > 0
499→      ) {
500→        return title;
501→      }
502→    }
503→
504→    // Strategy 3: Try to get from sidebar conversation list
505→    // Look for the active conversation in the sidebar
506→    try {
507→      // Gemini uses various selectors for conversation titles
508→      const selectors = [
509→        // Gemini sidebar active conversation
510→        'mat-list-item.mdc-list-item--activated [mat-line]',
511→        'mat-list-item[aria-current="page"] [mat-line]',
512→        // AI Studio active conversation
513→        '.conversation-list-item.active .conversation-title',
514→        '.active-conversation .title',
515→      ];
516→
517→      for (const selector of selectors) {
518→        const element = document.querySelector(selector);
519→        if (element && element.textContent) {
520→          const text = element.textContent.trim();
521→          if (text && text.length > 0 && text !== 'New chat') {
522→            return text;
523→          }
524→        }
525→      }
526→    } catch (error) {
527→      console.debug('[Timeline] Failed to get title from sidebar:', error);
528→    }
529→
530→    // Strategy 4: Use first user message as title (fallback)
531→    const firstMarker = this.markers[0];
532→    if (firstMarker && firstMarker.summary) {
533→      const preview = firstMarker.summary.slice(0, 50);
534→      return preview.length < firstMarker.summary.length ? `${preview}...` : preview;
535→    }
536→
537→    // Strategy 5: Extract from URL if it contains conversation ID
538→    try {
539→      const urlPath = window.location.pathname;
540→      const match = urlPath.match(/\/app\/([a-zA-Z0-9_-]+)/);
541→      if (match && match[1]) {
542→        return `Conversation ${match[1].slice(0, 8)}...`;
543→      }
544→    } catch (error) {
545→      console.debug('[Timeline] Failed to extract from URL:', error);
546→    }
547→
548→    // Final fallback: generic name
549→    return 'Untitled Conversation';
550→  }
