552→  private waitForElement(selector: string, timeoutMs: number = 5000): Promise<Element | null> {
553→    return new Promise((resolve) => {
554→      const found = document.querySelector(selector);
555→      if (found) return resolve(found);
556→      const obs = new MutationObserver(() => {
557→        const el = document.querySelector(selector);
558→        if (el) {
559→          try {
560→            obs.disconnect();
561→          } catch {}
562→          resolve(el);
563→        }
564→      });
565→      try {
566→        obs.observe(document.body, { childList: true, subtree: true });
567→      } catch {}
568→      if (timeoutMs > 0) {
569→        setTimeout(() => {
570→          try {
571→            obs.disconnect();
572→          } catch {}
573→          resolve(null);
574→        }, timeoutMs);
575→      }
576→    });
577→  }
578→
579→  private waitForAnyElement(
580→    selectors: string[],
581→    timeoutMs: number = 5000,
582→  ): Promise<{ element: Element; selector: string } | null> {
583→    return new Promise((resolve) => {
584→      for (const selector of selectors) {
585→        const found = document.querySelector(selector);
586→        if (found) return resolve({ element: found, selector });
587→      }
588→
589→      const obs = new MutationObserver(() => {
590→        for (const selector of selectors) {
591→          const el = document.querySelector(selector);
592→          if (el) {
593→            try {
594→              obs.disconnect();
595→            } catch {}
596→            resolve({ element: el, selector });
597→            return;
598→          }
599→        }
600→      });
601→
602→      try {
603→        obs.observe(document.body, { childList: true, subtree: true });
604→      } catch {}
605→
606→      if (timeoutMs > 0) {
607→        setTimeout(() => {
608→          try {
609→            obs.disconnect();
610→          } catch {}
611→          resolve(null);
612→        }, timeoutMs);
613→      }
614→    });
615→  }
