617→  private async findCriticalElements(): Promise<boolean> {
618→    const configured = this.getConfiguredUserTurnSelector();
619→    let userOverride = '';
620→    let autoDetected = '';
621→    try {
622→      userOverride = localStorage.getItem('geminiTimelineUserTurnSelector') || '';
623→      autoDetected = localStorage.getItem('geminiTimelineUserTurnSelectorAuto') || '';
624→    } catch {}
625→    const defaultCandidates = [
626→      // Angular-based Gemini UI user bubble (primary)
627→      '.user-query-bubble-with-background',
628→      // Angular containers (fallbacks if bubble selector changes)
629→      '.user-query-bubble-container',
630→      '.user-query-container',
631→      'user-query-content .user-query-bubble-with-background',
632→      // Attribute-based fallbacks for other Gemini variants
633→      'div[aria-label="User message"]',
634→      'article[data-author="user"]',
635→      'article[data-turn="user"]',
636→      '[data-message-author-role="user"]',
637→      'div[role="listitem"][data-user="true"]',
638→    ];
639→    // Compatibility strategy:
640→    // - Keep explicit user override as highest priority.
641→    // - Prefer built-in defaults over auto-detected cache, so stale auto cache can self-heal after refresh.
642→    let candidates = [...defaultCandidates];
643→    if (userOverride.length) {
644→      candidates = [userOverride, ...defaultCandidates.filter((s) => s !== userOverride)];
645→    } else {
646→      const cached = autoDetected || configured;
647→      if (cached && !candidates.includes(cached)) candidates.push(cached);
648→    }
649→    let firstTurn: Element | null = null;
650→    let matchedSelector = '';
651→    const found = await this.waitForAnyElement(candidates, 4000);
652→    if (found) {
653→      firstTurn = found.element;
654→      matchedSelector = found.selector;
655→      this.userTurnSelector = matchedSelector;
656→    }
657→    if (!firstTurn) {
658→      this.conversationContainer =
659→        (document.querySelector('main') as HTMLElement) || (document.body as HTMLElement);
660→      this.userTurnSelector = defaultCandidates.join(',');
661→    } else {
662→      // Scope selection/observers:
663→      // - Broad scope (main/body) if:
664→      //   a) user provided an explicit override, or
665→      //   b) auto-detected selector suggests Angular-based user query DOM (contains 'user-query')
666→      // - Otherwise, scope to the immediate parent for performance
667→      const looksAngularUserQuery = /user-query/i.test(matchedSelector || '');
668→      if ((userOverride && matchedSelector === userOverride) || looksAngularUserQuery) {
669→        this.conversationContainer =
670→          (document.querySelector('main') as HTMLElement) || (document.body as HTMLElement);
671→      } else {
672→        const parent = firstTurn.parentElement as HTMLElement | null;
673→        if (!parent) return false;
674→        this.conversationContainer = parent;
675→      }
676→      // Persist auto-detected selector for future sessions when no explicit user override exists
677→      if (!userOverride && matchedSelector) {
678→        try {
679→          localStorage.setItem('geminiTimelineUserTurnSelectorAuto', matchedSelector);
680→        } catch {}
681→      }
682→      // If a stale user override failed (matchedSelector differs), clear it so we don't keep retrying it
683→      if (userOverride && matchedSelector && matchedSelector !== userOverride) {
684→        try {
685→          localStorage.removeItem('geminiTimelineUserTurnSelector');
686→        } catch {}
687→      }
688→    }
689→    let p: HTMLElement | null = (firstTurn as HTMLElement) || this.conversationContainer;
690→    while (p && p !== document.body) {
691→      const st = getComputedStyle(p);
692→      if (st.overflowY === 'auto' || st.overflowY === 'scroll') {
693→        this.scrollContainer = p;
694→        break;
695→      }
696→      p = p.parentElement;
697→    }
698→    if (!this.scrollContainer)
699→      this.scrollContainer =
700→        (document.scrollingElement as HTMLElement) ||
701→        document.documentElement ||
702→        (document.body as unknown as HTMLElement);
703→    return true;
704→  }
