848→      if (this.hasVisuallyHiddenClass(clone)) return '';
849→
850→      // Remove visually-hidden descendants
851→      const descendants = clone.getElementsByTagName('*');
852→      for (let i = descendants.length - 1; i >= 0; i--) {
853→        if (this.hasVisuallyHiddenClass(descendants[i])) {
