143→/**
144→ * Cleanup function to prevent memory leaks
145→ * Disconnects all observers, clears intervals, and removes event listeners
146→ */
147→function cleanup(): void {
148→  // Cancel any pending delayed initialization
149→  if (urlChangeTimer) {
150→    clearTimeout(urlChangeTimer);
151→    urlChangeTimer = null;
152→  }
153→
154→  // Disconnect all active MutationObservers
155→  activeObservers.forEach((observer) => {
156→    try {
157→      observer.disconnect();
158→    } catch (e) {
159→      console.error('[Gemini Voyager] Failed to disconnect observer during cleanup:', e);
160→    }
161→  });
162→  activeObservers = [];
163→
164→  // Clear the route check interval
165→  if (routeCheckIntervalId !== null) {
166→    clearInterval(routeCheckIntervalId);
167→    routeCheckIntervalId = null;
168→  }
169→
170→  // Execute all registered cleanup handlers
171→  cleanupHandlers.forEach((handler) => {
172→    try {
173→      handler();
174→    } catch (e) {
175→      console.error('[Gemini Voyager] Failed to run cleanup handler:', e);
176→    }
177→  });
178→  cleanupHandlers = [];
179→
180→  // Reset flag
181→  routeListenersAttached = false;
182→}
183→
184→export function startTimeline(): void {
185→  const setup = (): void => {
186→    attachRouteListenersOnce();
187→    if (isGeminiConversationRoute() && !timelineManagerInstance) {
188→      initializeTimeline();
189→    }
190→  };
191→
192→  if (document.body) {
193→    setup();
194→  } else {
195→    const initialObserver = new MutationObserver(() => {
196→      if (!document.body) return;
197→
198→      // Disconnect and remove from tracking
199→      initialObserver.disconnect();
200→      activeObservers = activeObservers.filter((obs) => obs !== initialObserver);
201→
202→      setup();
203→    });
204→
205→    // Track observer for cleanup
206→    activeObservers.push(initialObserver);
207→    initialObserver.observe(document.documentElement || document.body, {
208→      childList: true,
209→      subtree: true,
210→    });
211→  }
212→
213→  // Setup cleanup on page unload
214→  window.addEventListener('beforeunload', cleanup, { once: true });
215→
216→  // Also cleanup on extension unload (if content script is removed)
217→  if (typeof chrome !== 'undefined' && chrome.runtime) {
218→    chrome.runtime.onSuspend?.addListener?.(cleanup);
219→  }
220→}
