  GV_FOLDER_TREE_INDENT: 'gvFolderTreeIndent',

  // Snow effect (legacy, kept for backward compat migration)
  GV_SNOW_EFFECT: 'gvSnowEffect',

  // Visual effect (replaces GV_SNOW_EFFECT): 'off' | 'snow' | 'sakura'
