  border-radius: 10px;
  padding: 6px 8px;
  display: inline-flex;
  gap: 8px;
  align-items: center;
  z-index: 2147483646;
  max-width: 280px;
  box-shadow: 0 8px 24px rgba(2, 6, 23, 0.4);
}

.gv-pm-confirm span {
  font-size: 12px;
  opacity: 0.95;
  line-height: 1.3;
  white-space: normal;
  flex: 1;
}

.gv-pm-confirm button {
  padding: 2px 8px;
  border-radius: 6px;
  border: 1px solid rgba(255, 255, 255, 0.18);
  background: rgba(31, 41, 55, 0.6);
  color: #e5e7eb;
  white-space: nowrap;
  font-size: 12px;
}

.gv-pm-confirm .gv-pm-confirm-yes {
  background: rgba(239, 68, 68, 0.18);
  border-color: rgba(239, 68, 68, 0.38);
  color: #fecaca;
}

.gv-pm-confirm button:hover {
  filter: brightness(1.05);
}

.gv-pm-confirm::after {
  content: '';
  position: absolute;
  width: 10px;
  height: 10px;
  background: rgba(2, 6, 23, 0.96);
  border: 1px solid rgba(255, 255, 255, 0.12);
  transform: rotate(45deg);
}

.gv-pm-confirm[data-side='left']::after {
  right: -6px;
  top: 50%;
  transform: translateY(-50%) rotate(45deg);
  border-left: none;
  border-bottom: none;
}

.gv-pm-confirm[data-side='right']::after {
  left: -6px;
  top: 50%;
  transform: translateY(-50%) rotate(45deg);
  border-right: none;
  border-top: none;
}

.gv-pm-drag {
  width: 10px;
  height: 14px;
  margin-left: -6px;
  margin-right: 6px;
  position: relative;
  opacity: 0.7;
