  content: '📁';
  font-size: 16px;
}

.gv-aistudio .google-symbols[data-icon='chat']::before {
  content: '💬';
  font-size: 16px;
}

.gv-aistudio .google-symbols[data-icon='push_pin']::before {
  content: '📌';
  font-size: 16px;
}

.gv-aistudio .gv-folder-pin-btn[data-state='unpinned'] .google-symbols::before {
  content: '📍';
  font-size: 14px;
}

.gv-aistudio
  .gv-folder-item[data-pinned='true']
  > .gv-folder-item-header
  .gv-folder-pin-btn
